import React, { useEffect } from "react";
import { Link } from "react-router-dom";
import Header from "../components/common/Header";
import Navbar from "../components/common/Navbar";
import logo from "../assets/cxotv-header-logo.jpg";
import BackgroundImage from "../assets/page2logo.jpg";
import Footer from "./Error"
const Error = () => {
  useEffect(() => {
    document.title = 'Page not found | CXOTV News';
  }, []);

  return (
    <div className="flex flex-col  w-full h-screen">
      <Header logo={logo} />
      <Navbar  />
      <div
      className="flex items-center justify-center my-10"
      style={{
        backgroundImage: `url(${BackgroundImage})`,
        backgroundSize: "cover",
        backgroundRepeat: "no-repeat",
        backgroundPosition: "center",
      }}
    >
      <p className="lg:text-[68px] text-white font-fira capitalize">
      404 Error
      </p>
    </div>
      <div className="flex flex-col items-center justify-center gap-8">
        <div className="text-red-600 font-roboto text-4xl font-bold">
          Oops! Page Not Found
        </div>
        <p className="text-gray-700 text-lg text-center">
        Sorry, We couldn’t find the page you’re looking for. Maybe Try one of the links in the navigation.
        </p>
        <Link
          className="py-2 px-4 bg-blue-700 text-white font-bold rounded-md hover:text-black hover:bg-white hover:border-spacing-2  "
          to={"/"}
        >
          Back to Home Page
        </Link>
      </div>
      <Footer/>
    </div>
  );
};

export default Error;